package com.fastfood.repository;

import com.fastfood.entity.transaction.SalesInvoice;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;

@Repository
public interface SalesInvoiceRepository extends JpaRepository<SalesInvoice, String> {

    @Query("SELECT MAX(s.idInvoice) FROM SalesInvoice s")
    String findMaxIdInvoice();

    @Query("""
            SELECT COALESCE(SUM(s.totalAmount), 0)
            FROM SalesInvoice s
            WHERE s.paymentDate >= :fromDateTime
              AND s.paymentDate < :toDateTime
            """)
    BigDecimal sumRevenueInRange(@Param("fromDateTime") LocalDateTime fromDateTime,
                                 @Param("toDateTime") LocalDateTime toDateTime);

    @Query("""
            SELECT COUNT(s)
            FROM SalesInvoice s
            WHERE s.paymentDate >= :fromDateTime
              AND s.paymentDate < :toDateTime
            """)
    long countInvoicesInRange(@Param("fromDateTime") LocalDateTime fromDateTime,
                              @Param("toDateTime") LocalDateTime toDateTime);
}

package com.fastfood.repository;

import java.time.LocalDate;
import java.util.List;

import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;

import com.fastfood.entity.transaction.StockReceipt;

public interface StockReceiptRepository extends JpaRepository<StockReceipt, String> {

    @Query("select max(s.idReceipt) from StockReceipt s")
    String findMaxIdReceipt();

    @Query("""
        select distinct s
        from StockReceipt s
        left join s.details d
        left join d.ingredient i
        where (:supplierName is null or lower(s.supplierName) like lower(concat('%', :supplierName, '%')))
          and (:fromDate is null or s.receiptDate >= :fromDate)
          and (:toDate is null or s.receiptDate <= :toDate)
          and (:ingredientId is null or i.idIngredient = :ingredientId)
        order by s.receiptDate desc, s.idReceipt desc
    """)
    List<StockReceipt> searchReceipts(
            @Param("supplierName") String supplierName,
            @Param("fromDate") LocalDate fromDate,
            @Param("toDate") LocalDate toDate,
            @Param("ingredientId") String ingredientId
    );
}

package com.fastfood.repository;

import java.time.LocalDate;
import java.util.List;
import java.math.BigDecimal;

import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;

import com.fastfood.entity.transaction.StockReceipt;

public interface StockReceiptRepository extends JpaRepository<StockReceipt, String> {

    @Query("select max(s.idReceipt) from StockReceipt s")
    String findMaxIdReceipt();

    @Query("""
        select distinct s
        from StockReceipt s
        left join s.details d
        left join d.ingredient i
        where (:supplierName is null or lower(s.supplierName) like lower(concat('%', :supplierName, '%')))
          and (:fromDate is null or s.receiptDate >= :fromDate)
          and (:toDate is null or s.receiptDate <= :toDate)
          and (:ingredientId is null or i.idIngredient = :ingredientId)
        order by s.receiptDate desc, s.idReceipt desc
    """)
    List<StockReceipt> searchReceipts(
            @Param("supplierName") String supplierName,
            @Param("fromDate") LocalDate fromDate,
            @Param("toDate") LocalDate toDate,
            @Param("ingredientId") String ingredientId
    );

    @Query("""
        select coalesce(sum(coalesce(d.quantityImport, 0) * coalesce(d.importPrice, 0)), 0)
        from StockReceipt s
        left join s.details d
        where s.receiptDate >= :fromDate
          and s.receiptDate <= :toDate
    """)
    BigDecimal sumImportCostInRange(@Param("fromDate") LocalDate fromDate,
                                    @Param("toDate") LocalDate toDate);

    @Query("""
        select count(s)
        from StockReceipt s
        where s.receiptDate >= :fromDate
          and s.receiptDate <= :toDate
    """)
    long countReceiptsInRange(@Param("fromDate") LocalDate fromDate,
                              @Param("toDate") LocalDate toDate);
}

package com.fastfood.service.impl;

import java.lang.reflect.Method;
import java.math.BigDecimal;
import java.sql.Date;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

import org.springframework.stereotype.Service;

import com.fastfood.dto.request.StockReceiptDetailRequest;
import com.fastfood.dto.request.StockReceiptRequest;
import com.fastfood.dto.response.InventoryConsumptionGroupResponse;
import com.fastfood.dto.response.InventoryConsumptionItemResponse;
import com.fastfood.dto.response.InventoryItemReportResponse;
import com.fastfood.dto.response.StockMovementDetailResponse;
import com.fastfood.dto.response.StockReceiptResponse;
import com.fastfood.entity.catalog.Ingredient;
import com.fastfood.entity.transaction.StockReceipt;
import com.fastfood.entity.transaction.StockReceiptDetail;
import com.fastfood.entity.transaction.StockReceiptDetailId;
import com.fastfood.repository.IngredientRepository;
import com.fastfood.repository.OrderDetailRepository;
import com.fastfood.repository.StockReceiptRepository;
import com.fastfood.service.IInventoryService;

import jakarta.transaction.Transactional;

@Service
public class InventoryImpl implements IInventoryService {

    private final IngredientRepository ingredientRepository;
    private final StockReceiptRepository stockReceiptRepository;
    private final OrderDetailRepository orderDetailRepository;

    public InventoryImpl(IngredientRepository ingredientRepository,
                         StockReceiptRepository stockReceiptRepository,
                         OrderDetailRepository orderDetailRepository) {
        this.ingredientRepository = ingredientRepository;
        this.stockReceiptRepository = stockReceiptRepository;
        this.orderDetailRepository = orderDetailRepository;
    }

    @Override
@Transactional
public StockReceiptResponse createStockReceipt(StockReceiptRequest request) {
    StockReceipt stockReceipt = StockReceipt.builder()
            .idReceipt(generateNextId(stockReceiptRepository.findMaxIdReceipt(), "PN"))
            .receiptDate(request.getReceiptDate())
            .supplierName(request.getSupplierName())
            .status(request.getStatus())
            .createdBy(request.getCreatedBy())
            .details(new ArrayList<>())
            .build();

    if (request.getDetails() != null) {
        for (StockReceiptDetailRequest detailRequest : request.getDetails()) {
            Ingredient ingredient = findIngredient(detailRequest.getIngredientId());

            StockReceiptDetail detail = StockReceiptDetail.builder()
                    .id(new StockReceiptDetailId(stockReceipt.getIdReceipt(), getIngredientId(ingredient)))
                    .stockReceipt(stockReceipt)
                    .ingredient(ingredient)
                    .quantityImport(detailRequest.getQuantityImport())
                    .importPrice(detailRequest.getImportPrice())
                    .build();

            stockReceipt.getDetails().add(detail);
        }
    }

    StockReceipt saved = stockReceiptRepository.save(stockReceipt);
    return toReceiptResponse(saved);
}

    @Override
    public List<StockReceiptResponse> getAllStockReceipts() {
        return stockReceiptRepository.findAll()
                .stream()
                .map(this::toReceiptResponse)
                .toList();
    }

    @Override
@Transactional
public StockReceiptResponse updateStockReceipt(String idReceipt, StockReceiptRequest request) {
    StockReceipt stockReceipt = stockReceiptRepository.findById(idReceipt)
            .orElseThrow(() -> new RuntimeException("Không tìm thấy phiếu nhập: " + idReceipt));

    String oldStatus = normalizeStatus(stockReceipt.getStatus());
    String newStatus = normalizeStatus(request.getStatus());

    // Chỉ cho cập nhật khi phiếu còn ở trạng thái CHỜ
    if (!"CHO".equals(oldStatus)) {
        throw new RuntimeException("Phiếu này đã cập nhật trạng thái, không thể thay đổi nữa");
    }

    if (request.getDetails() == null || request.getDetails().isEmpty()) {
        throw new RuntimeException("Phiếu nhập phải có ít nhất 1 nguyên liệu");
    }

    stockReceipt.setReceiptDate(request.getReceiptDate());
    stockReceipt.setSupplierName(request.getSupplierName());
    stockReceipt.setStatus(request.getStatus());
    stockReceipt.setCreatedBy(request.getCreatedBy());

    // Chỉ cộng kho khi NHẬN HÀNG
    if ("DA_NHAP".equals(newStatus)) {
        for (StockReceiptDetailRequest detailRequest : request.getDetails()) {
            Ingredient ingredient = findIngredient(detailRequest.getIngredientId());

            BigDecimal currentStock = getIngredientQuantityStock(ingredient);
            BigDecimal qty = detailRequest.getQuantityImport() == null
                    ? BigDecimal.ZERO
                    : detailRequest.getQuantityImport();

            setIngredientQuantityStock(ingredient, currentStock.add(qty));
            ingredientRepository.save(ingredient);
        }
    }

    // Nếu HOÀN TRẢ thì không cộng kho, chỉ đổi trạng thái

    StockReceipt saved = stockReceiptRepository.save(stockReceipt);
    return toReceiptResponse(saved);
}

    @Override
    @Transactional
    public void deleteStockReceipt(String idReceipt) {
        StockReceipt stockReceipt = stockReceiptRepository.findById(idReceipt)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy phiếu nhập: " + idReceipt));

        if (stockReceipt.getDetails() != null) {
            for (StockReceiptDetail detail : stockReceipt.getDetails()) {
                Ingredient ingredient = detail.getIngredient();
                BigDecimal currentStock = getIngredientQuantityStock(ingredient);
                BigDecimal qty = detail.getQuantityImport() == null
                        ? BigDecimal.ZERO
                        : detail.getQuantityImport();

                setIngredientQuantityStock(ingredient, currentStock.subtract(qty));
                ingredientRepository.save(ingredient);
            }
        }

        stockReceiptRepository.delete(stockReceipt);
    }

    @Override
    public List<StockReceiptResponse> searchStockReceipts(String supplierName,
                                                          LocalDate fromDate,
                                                          LocalDate toDate,
                                                          String ingredientId) {
        return stockReceiptRepository.searchReceipts(
                        emptyToNull(supplierName),
                        fromDate,
                        toDate,
                        emptyToNull(ingredientId)
                )
                .stream()
                .map(this::toReceiptResponse)
                .toList();
    }

    @Override
    public List<InventoryItemReportResponse> getInventoryReport() {
        return ingredientRepository.findAll()
                .stream()
                .map(this::toInventoryItemReport)
                .toList();
    }

    @Override
    public List<InventoryItemReportResponse> getLowStockItems() {
        return ingredientRepository.findAll()
                .stream()
                .filter(ingredient -> getIngredientQuantityStock(ingredient).compareTo(BigDecimal.TEN) <= 0)
                .map(this::toInventoryItemReport)
                .toList();
    }

    @Override
    public List<InventoryConsumptionGroupResponse> getConsumptionHistory(LocalDate fromDate, LocalDate toDate) {
        List<Object[]> rows = orderDetailRepository.getIngredientConsumptionHistory(fromDate, toDate);

        Map<LocalDate, List<InventoryConsumptionItemResponse>> grouped = new LinkedHashMap<>();

        for (Object[] row : rows) {
            LocalDate date = toLocalDate(row[0]);
            if (date == null) {
                continue;
            }

            String ingredientId = row[1] != null ? row[1].toString() : null;
            String imageUrlIngredient = row[2] != null ? row[2].toString() : null;
            String ingredientName = row[3] != null ? row[3].toString() : null;
            String unit = row[4] != null ? row[4].toString() : null;
            BigDecimal currentStock = toBigDecimal(row[5]);
            BigDecimal consumedQuantity = toBigDecimal(row[6]);

            grouped.computeIfAbsent(date, k -> new ArrayList<>())
                    .add(
                            InventoryConsumptionItemResponse.builder()
                                    .ingredientId(ingredientId)
                                    .imageUrlIngredient(imageUrlIngredient)
                                    .ingredientName(ingredientName)
                                    .unit(unit)
                                    .currentStock(currentStock)
                                    .consumedQuantity(consumedQuantity)
                                    .build()
                    );
        }

        List<InventoryConsumptionGroupResponse> result = new ArrayList<>();
        for (Map.Entry<LocalDate, List<InventoryConsumptionItemResponse>> entry : grouped.entrySet()) {
            result.add(
                    InventoryConsumptionGroupResponse.builder()
                            .date(entry.getKey())
                            .items(entry.getValue())
                            .build()
            );
        }

        return result;
    }

    private Ingredient findIngredient(String idIngredient) {
        return ingredientRepository.findById(idIngredient)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy nguyên liệu: " + idIngredient));
    }

    private String generateNextId(String maxId, String prefix) {
        if (maxId == null) {
            return prefix + "001";
        }
        int next = Integer.parseInt(maxId.substring(prefix.length())) + 1;
        return String.format("%s%03d", prefix, next);
    }

    private String emptyToNull(String value) {
        if (value == null || value.trim().isEmpty()) {
            return null;
        }
        return value.trim();
    }

    private StockReceiptResponse toReceiptResponse(StockReceipt stockReceipt) {
        List<StockMovementDetailResponse> detailResponses = new ArrayList<>();

        if (stockReceipt.getDetails() != null) {
            for (StockReceiptDetail detail : stockReceipt.getDetails()) {
                detailResponses.add(
                        StockMovementDetailResponse.builder()
                                .ingredientId(getIngredientId(detail.getIngredient()))
                                .imageUrlIngredient(getIngredientImageUrl(detail.getIngredient()))
                                .ingredientName(getIngredientName(detail.getIngredient()))
                                .quantityImport(detail.getQuantityImport())
                                .importPrice(detail.getImportPrice())
                                .build()
                );
            }
        }

        return StockReceiptResponse.builder()
                .idReceipt(stockReceipt.getIdReceipt())
                .receiptDate(stockReceipt.getReceiptDate())
                .supplierName(stockReceipt.getSupplierName())
                .status(stockReceipt.getStatus())
                .createdBy(stockReceipt.getCreatedBy())
                .details(detailResponses)
                .build();
    }

    private InventoryItemReportResponse toInventoryItemReport(Ingredient ingredient) {
        BigDecimal stock = getIngredientQuantityStock(ingredient);

        return InventoryItemReportResponse.builder()
                .ingredientId(getIngredientId(ingredient))
                .imageUrlIngredient(getIngredientImageUrl(ingredient))
                .ingredientName(getIngredientName(ingredient))
                .unit(getIngredientUnit(ingredient))
                .currentStock(stock)
                .minStock(BigDecimal.TEN)
                .lowStock(stock.compareTo(BigDecimal.TEN) <= 0)
                .build();
    }

    private BigDecimal getIngredientQuantityStock(Ingredient ingredient) {
        try {
            Method method = ingredient.getClass().getMethod("getQuantityStock");
            Object value = method.invoke(ingredient);
            return value == null ? BigDecimal.ZERO : (BigDecimal) value;
        } catch (Exception ignored) {
        }

        return BigDecimal.ZERO;
    }

    private void setIngredientQuantityStock(Ingredient ingredient, BigDecimal value) {
        try {
            Method method = ingredient.getClass().getMethod("setQuantityStock", BigDecimal.class);
            method.invoke(ingredient, value);
        } catch (Exception e) {
            throw new RuntimeException("Không thể cập nhật số lượng tồn kho cho nguyên liệu");
        }
    }

    private String getIngredientId(Ingredient ingredient) {
        try {
            Method method = ingredient.getClass().getMethod("getIdIngredient");
            Object value = method.invoke(ingredient);
            return value == null ? null : value.toString();
        } catch (Exception e) {
            throw new RuntimeException("Không thể lấy mã nguyên liệu");
        }
    }

    private String getIngredientName(Ingredient ingredient) {
        try {
            Method method = ingredient.getClass().getMethod("getIngredientName");
            Object value = method.invoke(ingredient);
            return value == null ? null : value.toString();
        } catch (Exception e) {
            return null;
        }
    }

    private String getIngredientUnit(Ingredient ingredient) {
        try {
            Method method = ingredient.getClass().getMethod("getUnit");
            Object value = method.invoke(ingredient);
            return value == null ? null : value.toString();
        } catch (Exception e) {
            return null;
        }
    }

    private String getIngredientImageUrl(Ingredient ingredient) {
        try {
            Method method = ingredient.getClass().getMethod("getImageUrlIngredient");
            Object value = method.invoke(ingredient);
            return value == null ? null : value.toString();
        } catch (Exception e) {
            return null;
        }
    }

    private LocalDate toLocalDate(Object value) {
        if (value == null) return null;
        if (value instanceof LocalDate localDate) return localDate;
        if (value instanceof Date sqlDate) return sqlDate.toLocalDate();
        return LocalDate.parse(value.toString());
    }

    private BigDecimal toBigDecimal(Object value) {
        if (value == null) return BigDecimal.ZERO;
        if (value instanceof BigDecimal bigDecimal) return bigDecimal;
        return new BigDecimal(value.toString());
    }


    private String normalizeStatus(String status) {
    if (status == null) return "CHO";

    String value = status.trim().toUpperCase();

    if ("PENDING".equals(value) || "CHO".equals(value)) return "CHO";
    if ("RECEIVED".equals(value) || "DA_NHAP".equals(value) || "NHAN_HANG".equals(value)) return "DA_NHAP";
    if ("CANCELLED".equals(value) || "RETURNED".equals(value) || "HOAN_TRA".equals(value)) return "HOAN_TRA";

    return value;
}
}

package com.fastfood.service.impl;

import java.math.BigDecimal;
import java.sql.Date;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

import org.springframework.stereotype.Service;

import com.fastfood.dto.request.StockReceiptDetailRequest;
import com.fastfood.dto.request.StockReceiptRequest;
import com.fastfood.dto.response.InventoryConsumptionGroupResponse;
import com.fastfood.dto.response.InventoryConsumptionItemResponse;
import com.fastfood.dto.response.InventoryItemReportResponse;
import com.fastfood.dto.response.StockMovementDetailResponse;
import com.fastfood.dto.response.StockReceiptResponse;
import com.fastfood.entity.catalog.Ingredient;
import com.fastfood.entity.transaction.StockReceipt;
import com.fastfood.entity.transaction.StockReceiptDetail;
import com.fastfood.entity.transaction.StockReceiptDetailId;
import com.fastfood.repository.IngredientRepository;
import com.fastfood.repository.OrderDetailRepository;
import com.fastfood.repository.StockReceiptRepository;
import com.fastfood.service.IInventoryService;

import jakarta.transaction.Transactional;

@Service
public class InventoryImpl implements IInventoryService {

    private final IngredientRepository ingredientRepository;
    private final StockReceiptRepository stockReceiptRepository;
    private final OrderDetailRepository orderDetailRepository;

    public InventoryImpl(IngredientRepository ingredientRepository,
                         StockReceiptRepository stockReceiptRepository,
                         OrderDetailRepository orderDetailRepository) {
        this.ingredientRepository = ingredientRepository;
        this.stockReceiptRepository = stockReceiptRepository;
        this.orderDetailRepository = orderDetailRepository;
    }

    @Override
    @Transactional
    public StockReceiptResponse createStockReceipt(StockReceiptRequest request) {
        if (request.getDetails() == null || request.getDetails().isEmpty()) {
            throw new RuntimeException("Phiếu nhập phải có ít nhất 1 nguyên liệu");
        }

        StockReceipt stockReceipt = StockReceipt.builder()
                .idReceipt(generateNextReceiptId(stockReceiptRepository.findMaxIdReceipt()))
                .receiptDate(request.getReceiptDate())
                .supplierName(request.getSupplierName())
                .status(normalizeStatus(request.getStatus()))
                .createdBy(request.getCreatedBy())
                .details(new ArrayList<>())
                .build();

        for (StockReceiptDetailRequest detailRequest : request.getDetails()) {
            stockReceipt.getDetails().add(toStockReceiptDetail(stockReceipt, detailRequest));
        }

        StockReceipt saved = stockReceiptRepository.save(stockReceipt);
        return toReceiptResponse(saved);
    }

    @Override
    public List<StockReceiptResponse> getAllStockReceipts() {
        return stockReceiptRepository.findAll()
                .stream()
                .map(this::toReceiptResponse)
                .toList();
    }

    @Override
    @Transactional
    public StockReceiptResponse updateStockReceipt(String idReceipt, StockReceiptRequest request) {
        StockReceipt stockReceipt = stockReceiptRepository.findById(idReceipt)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy phiếu nhập: " + idReceipt));

        String oldStatus = normalizeStatus(stockReceipt.getStatus());
        String newStatus = normalizeStatus(request.getStatus());

        // Chỉ cho cập nhật khi phiếu còn ở trạng thái chờ.
        if (!"CHO".equals(oldStatus)) {
            throw new RuntimeException("Phiếu này đã cập nhật trạng thái, không thể thay đổi nữa");
        }

        if (request.getDetails() == null || request.getDetails().isEmpty()) {
            throw new RuntimeException("Phiếu nhập phải có ít nhất 1 nguyên liệu");
        }

        stockReceipt.setReceiptDate(request.getReceiptDate());
        stockReceipt.setSupplierName(request.getSupplierName());
        stockReceipt.setStatus(newStatus);
        stockReceipt.setCreatedBy(request.getCreatedBy());

        stockReceipt.getDetails().clear();
        for (StockReceiptDetailRequest detailRequest : request.getDetails()) {
            stockReceipt.getDetails().add(toStockReceiptDetail(stockReceipt, detailRequest));
        }

        // Chỉ cộng kho khi chuyển sang đã nhập hàng.
        if ("DA_NHAP".equals(newStatus)) {
            for (StockReceiptDetail detail : stockReceipt.getDetails()) {
                Ingredient ingredient = detail.getIngredient();
                BigDecimal currentStock = getIngredientQuantityStock(ingredient);
                BigDecimal qty = detail.getQuantityImport() == null ? BigDecimal.ZERO : detail.getQuantityImport();
                setIngredientQuantityStock(ingredient, currentStock.add(qty));
                ingredientRepository.save(ingredient);
            }
        }

        StockReceipt saved = stockReceiptRepository.save(stockReceipt);
        return toReceiptResponse(saved);
    }

    @Override
    @Transactional
    public void deleteStockReceipt(String idReceipt) {
        StockReceipt stockReceipt = stockReceiptRepository.findById(idReceipt)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy phiếu nhập: " + idReceipt));

        // Chỉ trừ kho khi phiếu đã từng cộng kho (DA_NHAP).
        if ("DA_NHAP".equals(normalizeStatus(stockReceipt.getStatus())) && stockReceipt.getDetails() != null) {
            for (StockReceiptDetail detail : stockReceipt.getDetails()) {
                Ingredient ingredient = detail.getIngredient();
                BigDecimal currentStock = getIngredientQuantityStock(ingredient);
                BigDecimal qty = detail.getQuantityImport() == null
                        ? BigDecimal.ZERO
                        : detail.getQuantityImport();

                setIngredientQuantityStock(ingredient, currentStock.subtract(qty));
                ingredientRepository.save(ingredient);
            }
        }

        stockReceiptRepository.delete(stockReceipt);
    }

    @Override
    public List<StockReceiptResponse> searchStockReceipts(String supplierName,
                                                          LocalDate fromDate,
                                                          LocalDate toDate,
                                                          String ingredientId) {
        return stockReceiptRepository.searchReceipts(
                        emptyToNull(supplierName),
                        fromDate,
                        toDate,
                        emptyToNull(ingredientId)
                )
                .stream()
                .map(this::toReceiptResponse)
                .toList();
    }

    @Override
    public List<InventoryItemReportResponse> getInventoryReport() {
        return ingredientRepository.findAll()
                .stream()
                .map(this::toInventoryItemReport)
                .toList();
    }

    @Override
    public List<InventoryItemReportResponse> getLowStockItems() {
        return ingredientRepository.findAll()
                .stream()
                .filter(ingredient -> getIngredientQuantityStock(ingredient).compareTo(BigDecimal.TEN) <= 0)
                .map(this::toInventoryItemReport)
                .toList();
    }

    @Override
    public List<InventoryConsumptionGroupResponse> getConsumptionHistory(LocalDate fromDate, LocalDate toDate) {
        List<Object[]> rows = orderDetailRepository.getIngredientConsumptionHistory(fromDate, toDate);

        Map<LocalDate, List<InventoryConsumptionItemResponse>> grouped = new LinkedHashMap<>();

        for (Object[] row : rows) {
            LocalDate date = toLocalDate(row[0]);
            if (date == null) {
                continue;
            }

            String ingredientId = row[1] != null ? row[1].toString() : null;
            String imageUrlIngredient = row[2] != null ? row[2].toString() : null;
            String ingredientName = row[3] != null ? row[3].toString() : null;
            String unit = row[4] != null ? row[4].toString() : null;
            BigDecimal currentStock = toBigDecimal(row[5]);
            BigDecimal consumedQuantity = toBigDecimal(row[6]);

            grouped.computeIfAbsent(date, k -> new ArrayList<>())
                    .add(
                            InventoryConsumptionItemResponse.builder()
                                    .ingredientId(ingredientId)
                                    .imageUrlIngredient(imageUrlIngredient)
                                    .ingredientName(ingredientName)
                                    .unit(unit)
                                    .currentStock(currentStock)
                                    .consumedQuantity(consumedQuantity)
                                    .build()
                    );
        }

        List<InventoryConsumptionGroupResponse> result = new ArrayList<>();
        for (Map.Entry<LocalDate, List<InventoryConsumptionItemResponse>> entry : grouped.entrySet()) {
            result.add(
                    InventoryConsumptionGroupResponse.builder()
                            .date(entry.getKey())
                            .items(entry.getValue())
                            .build()
            );
        }

        return result;
    }

    private StockReceiptDetail toStockReceiptDetail(StockReceipt stockReceipt, StockReceiptDetailRequest detailRequest) {
        Ingredient ingredient = findIngredient(detailRequest.getIngredientId());
        return StockReceiptDetail.builder()
                .id(new StockReceiptDetailId(stockReceipt.getIdReceipt(), ingredient.getIdIngredient()))
                .stockReceipt(stockReceipt)
                .ingredient(ingredient)
                .quantityImport(detailRequest.getQuantityImport())
                .importPrice(detailRequest.getImportPrice())
                .build();
    }

    private Ingredient findIngredient(String idIngredient) {
        return ingredientRepository.findById(idIngredient)
                .orElseThrow(() -> new RuntimeException("Không tìm thấy nguyên liệu: " + idIngredient));
    }

    private String generateNextReceiptId(String maxId) {
        String prefix = "PN";
        if (maxId == null) {
            return prefix + "001";
        }
        int next = Integer.parseInt(maxId.substring(prefix.length())) + 1;
        return String.format("%s%03d", prefix, next);
    }

    private String emptyToNull(String value) {
        if (value == null || value.trim().isEmpty()) {
            return null;
        }
        return value.trim();
    }

    private StockReceiptResponse toReceiptResponse(StockReceipt stockReceipt) {
        List<StockMovementDetailResponse> detailResponses = new ArrayList<>();

        if (stockReceipt.getDetails() != null) {
            for (StockReceiptDetail detail : stockReceipt.getDetails()) {
                detailResponses.add(
                        StockMovementDetailResponse.builder()
                                .ingredientId(getIngredientId(detail.getIngredient()))
                                .imageUrlIngredient(getIngredientImageUrl(detail.getIngredient()))
                                .ingredientName(getIngredientName(detail.getIngredient()))
                                .quantityImport(detail.getQuantityImport())
                                .importPrice(detail.getImportPrice())
                                .build()
                );
            }
        }

        return StockReceiptResponse.builder()
                .idReceipt(stockReceipt.getIdReceipt())
                .receiptDate(stockReceipt.getReceiptDate())
                .supplierName(stockReceipt.getSupplierName())
                .status(stockReceipt.getStatus())
                .createdBy(stockReceipt.getCreatedBy())
                .details(detailResponses)
                .build();
    }

    private InventoryItemReportResponse toInventoryItemReport(Ingredient ingredient) {
        BigDecimal stock = getIngredientQuantityStock(ingredient);

        return InventoryItemReportResponse.builder()
                .ingredientId(getIngredientId(ingredient))
                .imageUrlIngredient(getIngredientImageUrl(ingredient))
                .ingredientName(getIngredientName(ingredient))
                .unit(getIngredientUnit(ingredient))
                .currentStock(stock)
                .minStock(BigDecimal.TEN)
                .lowStock(stock.compareTo(BigDecimal.TEN) <= 0)
                .build();
    }

    private BigDecimal getIngredientQuantityStock(Ingredient ingredient) {
        return ingredient.getQuantityStock() == null ? BigDecimal.ZERO : ingredient.getQuantityStock();
    }

    private void setIngredientQuantityStock(Ingredient ingredient, BigDecimal value) {
        ingredient.setQuantityStock(value);
    }

    private String getIngredientId(Ingredient ingredient) {
        return ingredient.getIdIngredient();
    }

    private String getIngredientName(Ingredient ingredient) {
        return ingredient.getIngredientName();
    }

    private String getIngredientUnit(Ingredient ingredient) {
        return ingredient.getUnit();
    }

    private String getIngredientImageUrl(Ingredient ingredient) {
        return ingredient.getImageUrlIngredient();
    }

    private LocalDate toLocalDate(Object value) {
        if (value == null) return null;
        if (value instanceof LocalDate localDate) return localDate;
        if (value instanceof Date sqlDate) return sqlDate.toLocalDate();
        return LocalDate.parse(value.toString());
    }

    private BigDecimal toBigDecimal(Object value) {
        if (value == null) return BigDecimal.ZERO;
        if (value instanceof BigDecimal bigDecimal) return bigDecimal;
        return new BigDecimal(value.toString());
    }
    private String normalizeStatus(String status) {
        if (status == null) return "CHO";

        String value = status.trim().toUpperCase();

        if ("PENDING".equals(value) || "CHO".equals(value)) return "CHO";
        if ("RECEIVED".equals(value) || "DA_NHAP".equals(value) || "NHAN_HANG".equals(value)) return "DA_NHAP";
        if ("CANCELLED".equals(value) || "RETURNED".equals(value) || "HOAN_TRA".equals(value)) return "HOAN_TRA";

        return value;
    }
}

package com.fastfood.service.impl;

import com.fastfood.dto.request.StockReceiptDetailRequest;
import com.fastfood.dto.request.StockReceiptRequest;
import com.fastfood.dto.response.StockReceiptResponse;
import com.fastfood.entity.catalog.Ingredient;
import com.fastfood.entity.transaction.StockReceipt;
import com.fastfood.entity.transaction.StockReceiptDetail;
import com.fastfood.entity.transaction.StockReceiptDetailId;
import com.fastfood.repository.IngredientRepository;
import com.fastfood.repository.OrderDetailRepository;
import com.fastfood.repository.StockReceiptRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.times;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class InventoryImplTest {

    @Mock
    private IngredientRepository ingredientRepository;

    @Mock
    private StockReceiptRepository stockReceiptRepository;

    @Mock
    private OrderDetailRepository orderDetailRepository;

    private InventoryImpl inventoryService;

    @BeforeEach
    void setUp() {
        inventoryService = new InventoryImpl(ingredientRepository, stockReceiptRepository, orderDetailRepository);
    }

    @Test
    void updateStockReceipt_whenChoToDaNhap_shouldIncreaseStock() {
        Ingredient ingredient = buildIngredient("NL001", new BigDecimal("10"));
        StockReceipt receipt = buildReceipt("PN001", "CHO", new ArrayList<>());

        StockReceiptRequest request = StockReceiptRequest.builder()
                .receiptDate(LocalDate.now())
                .supplierName("NCC A")
                .status("DA_NHAP")
                .createdBy("U_001")
                .details(List.of(buildDetailRequest("NL001", "2")))
                .build();

        when(stockReceiptRepository.findById("PN001")).thenReturn(Optional.of(receipt));
        when(ingredientRepository.findById("NL001")).thenReturn(Optional.of(ingredient));
        when(stockReceiptRepository.save(any(StockReceipt.class))).thenAnswer(invocation -> invocation.getArgument(0));

        StockReceiptResponse response = inventoryService.updateStockReceipt("PN001", request);

        assertNotNull(response);
        assertEquals("DA_NHAP", response.getStatus());
        assertEquals(new BigDecimal("12"), ingredient.getQuantityStock());
        verify(ingredientRepository, times(1)).save(ingredient);
    }

    @Test
    void updateStockReceipt_whenChoToHoanTra_shouldNotIncreaseStock() {
        Ingredient ingredient = buildIngredient("NL001", new BigDecimal("10"));
        StockReceipt receipt = buildReceipt("PN001", "CHO", new ArrayList<>());

        StockReceiptRequest request = StockReceiptRequest.builder()
                .receiptDate(LocalDate.now())
                .supplierName("NCC A")
                .status("HOAN_TRA")
                .createdBy("U_001")
                .details(List.of(buildDetailRequest("NL001", "2")))
                .build();

        when(stockReceiptRepository.findById("PN001")).thenReturn(Optional.of(receipt));
        when(ingredientRepository.findById("NL001")).thenReturn(Optional.of(ingredient));
        when(stockReceiptRepository.save(any(StockReceipt.class))).thenAnswer(invocation -> invocation.getArgument(0));

        StockReceiptResponse response = inventoryService.updateStockReceipt("PN001", request);

        assertNotNull(response);
        assertEquals("HOAN_TRA", response.getStatus());
        assertEquals(new BigDecimal("10"), ingredient.getQuantityStock());
        verify(ingredientRepository, never()).save(any(Ingredient.class));
    }

    @Test
    void deleteStockReceipt_whenDaNhap_shouldRollbackStock() {
        Ingredient ingredient = buildIngredient("NL001", new BigDecimal("10"));

        StockReceipt receipt = buildReceipt("PN001", "DA_NHAP", new ArrayList<>());
        StockReceiptDetail detail = StockReceiptDetail.builder()
                .id(new StockReceiptDetailId("PN001", "NL001"))
                .stockReceipt(receipt)
                .ingredient(ingredient)
                .quantityImport(new BigDecimal("3"))
                .importPrice(new BigDecimal("10000"))
                .build();
        receipt.getDetails().add(detail);

        when(stockReceiptRepository.findById("PN001")).thenReturn(Optional.of(receipt));

        inventoryService.deleteStockReceipt("PN001");

        assertEquals(new BigDecimal("7"), ingredient.getQuantityStock());
        verify(ingredientRepository, times(1)).save(ingredient);
        verify(stockReceiptRepository, times(1)).delete(receipt);
    }

    private Ingredient buildIngredient(String id, BigDecimal stock) {
        Ingredient ingredient = new Ingredient();
        ingredient.setIdIngredient(id);
        ingredient.setIngredientName("Nguyen lieu test");
        ingredient.setUnit("kg");
        ingredient.setQuantityStock(stock);
        return ingredient;
    }

    private StockReceipt buildReceipt(String id, String status, List<StockReceiptDetail> details) {
        StockReceipt receipt = new StockReceipt();
        receipt.setIdReceipt(id);
        receipt.setReceiptDate(LocalDate.now());
        receipt.setSupplierName("NCC");
        receipt.setStatus(status);
        receipt.setCreatedBy("U_001");
        receipt.setDetails(details);
        return receipt;
    }

    private StockReceiptDetailRequest buildDetailRequest(String ingredientId, String qty) {
        return StockReceiptDetailRequest.builder()
                .ingredientId(ingredientId)
                .quantityImport(new BigDecimal(qty))
                .importPrice(new BigDecimal("10000"))
                .build();
    }
}

import React from 'react';
import { BrowserRouter, Routes, Route, Link, Outlet, Navigate, useLocation, useNavigate } from 'react-router-dom';
import { Button, Layout, Menu, Typography } from 'antd';
import {
  AppstoreOutlined,
  CreditCardOutlined,
  DashboardOutlined,
  DatabaseOutlined,
  FireOutlined,
  LogoutOutlined,
  OrderedListOutlined
} from '@ant-design/icons';

// Các trang giao diện
import FoodMenu from './pages/FoodMenu';
import KitchenPage from './pages/KitchenPage';
import PaymentPage from './pages/PaymentPage';
import Login from './pages/Login';
import AdminDashboard from './pages/AdminDashboard';
import InventoryPage from './pages/InventoryPage';

// Import trang MenuAdmin 
import MenuAdmin from './pages/MenuAdmin'; 

const OrdersPage = () => <div style={{ padding: 20 }}><h1>Màn hình Đơn hàng</h1></div>;

const { Header, Content, Footer, Sider } = Layout;
const { Title } = Typography;

const normalizeRole = (role) => {
  const normalized = (role || '').trim().toLowerCase();
  if (normalized === 'admin') return 'ADMIN';
  if (normalized === 'thu ngân' || normalized === 'thu ngan') return 'Thu ngân';
  if (normalized === 'bếp' || normalized === 'bep') return 'Bếp';
  if (normalized === 'khách hàng' || normalized === 'khach hang') return 'Khách hàng';
  return role || '';
};

const getStoredRole = () => normalizeRole(localStorage.getItem('userRole'));

const getRoleHomePath = (role) => {
  const normalizedRole = normalizeRole(role);
  if (normalizedRole === 'ADMIN') return '/admin/dashboard'; 
  if (normalizedRole === 'Thu ngân') return '/payment';
  if (normalizedRole === 'Bếp') return '/kitchen';
  if (normalizedRole === 'Khách hàng') return '/menu';
  return '/login';
};

const isRoleNavigable = (role) => getRoleHomePath(role) !== '/login';

const ProtectedRoute = ({ children, allowedRoles }) => {
  const role = getStoredRole();
  if (!role) return <Navigate to="/login" replace />;
  if (allowedRoles && !allowedRoles.map(normalizeRole).includes(role)) {
    return <Navigate to={getRoleHomePath(role)} replace />;
  }
  return children;
};

const HomeRedirect = () => {
  return <Navigate to={getRoleHomePath(getStoredRole())} replace />;
};

// ========================================================
//  TÁCH RIÊNG MENU CỦA ADMIN VÀ KHÁCH
// ========================================================
const menuItems = [
  // 1. Nhóm nút chỉ hiện cho ADMIN
  { key: 'dashboard', path: '/admin/dashboard', label: 'Dashboard', icon: <DashboardOutlined />, roles: ['ADMIN'] },
  { key: 'orders', path: '/admin/orders', label: 'Đơn hàng', icon: <OrderedListOutlined />, roles: ['ADMIN'] },
  { key: 'admin-menu', path: '/admin/menu', label: 'Quản lý Menu', icon: <AppstoreOutlined />, roles: ['ADMIN'] }, // Sẽ mở MenuAdmin
  { key: 'inventory', path: '/admin/inventory', label: 'Kho', icon: <DatabaseOutlined />, roles: ['ADMIN'] },

  // 2. Nhóm nút cho KHÁCH & THU NGÂN
  { key: 'customer-menu', path: '/menu', label: 'Menu Đặt Món', icon: <AppstoreOutlined />, roles: ['Khách hàng', 'Thu ngân'] }, // Sẽ mở FoodMenu màu cam

  // 3. Nhóm nút cho BẾP
  { key: 'kitchen', path: '/kitchen', label: 'Bếp', icon: <FireOutlined />, roles: ['Bếp'] },
  { key: 'payment', path: '/payment', label: 'Thanh Toán', icon: <CreditCardOutlined />, roles: ['Thu ngân'] }
];

const MainLayout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const role = getStoredRole();

  const visibleMenuItems = menuItems.filter((item) => item.roles.map(normalizeRole).includes(role));
  const selectedKey = menuItems.find((item) => item.path === location.pathname)?.key || '';

  const handleLogout = () => {
    localStorage.removeItem('userRole');
    localStorage.removeItem('username');
    localStorage.removeItem('fullName');
    localStorage.removeItem('tableNumber');
    navigate('/login', { replace: true });
  };

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Sider theme="dark" breakpoint="lg" collapsedWidth="0">
        <div style={{ height: 32, margin: 16, background: 'rgba(255, 255, 255, 0.2)', borderRadius: 6, display: 'flex', justifyContent: 'center', alignItems: 'center', color: 'white', fontWeight: 'bold' }}>
          HỆ THỐNG POS
        </div>

        <Menu theme="dark" mode="inline" selectedKeys={[selectedKey]}>
          {visibleMenuItems.map((item) => (
            <Menu.Item key={item.key} icon={item.icon}>
              <Link to={item.path}>{item.label}</Link>
            </Menu.Item>
          ))}
        </Menu>
      </Sider>

      <Layout>
        <Header style={{ background: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 20px' }}>
          <Title level={4} style={{ margin: 0 }}>FastFood Dashboard</Title>
          <Button icon={<LogoutOutlined />} onClick={handleLogout}>Đăng xuất</Button>
        </Header>

        <Content style={{ margin: '24px 16px 0' }}>
          <div style={{ minHeight: 360, background: '#fff', borderRadius: 8 }}>
            <Outlet />
          </div>
        </Content>
      </Layout>
    </Layout>
  );
};

function App() {
  const role = getStoredRole();
  const roleHomePath = getRoleHomePath(role);

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={role && isRoleNavigable(role) ? <Navigate to={roleHomePath} replace /> : <Login />} />

        <Route element={<ProtectedRoute><MainLayout /></ProtectedRoute>}>
          <Route path="/" element={<HomeRedirect />} />

          {/* ========================================================
              CẤP ROUTE CHUẨN CHO ADMIN
              ======================================================== */}
          <Route path="/admin">
            <Route path="dashboard" element={<ProtectedRoute allowedRoles={['ADMIN']}><AdminDashboard /></ProtectedRoute>} />
            <Route path="orders" element={<ProtectedRoute allowedRoles={['ADMIN']}><OrdersPage /></ProtectedRoute>} />

            {/* Nhét MenuAdmin vào đường dẫn /admin/menu */}
            <Route path="menu" element={<ProtectedRoute allowedRoles={['ADMIN']}><MenuAdmin /></ProtectedRoute>} />

            <Route path="inventory" element={<ProtectedRoute allowedRoles={['ADMIN']}><InventoryPage /></ProtectedRoute>} />
          </Route>

          {/* Các trang của Role khác */}
          <Route path="/menu" element={<ProtectedRoute allowedRoles={['Khách hàng', 'Thu ngân']}><FoodMenu /></ProtectedRoute>} />
          <Route path="/pos" element={<Navigate to="/menu" replace />} />
          <Route path="/kitchen" element={<ProtectedRoute allowedRoles={['Bếp']}><KitchenPage /></ProtectedRoute>} />
          <Route path="/payment" element={<ProtectedRoute allowedRoles={['Thu ngân']}><PaymentPage /></ProtectedRoute>} />
        </Route>

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;

import React, { useEffect, useMemo, useState } from 'react';
import { message, Empty, Spin } from 'antd';
import axios from 'axios';
import '../css/InventoryPage.css';

const API_BASE_URL = 'http://localhost:8080/api';
const DEFAULT_RECEIPT_STATUS = 'CHO';

const IngredientImage = ({ src, alt }) => {
  const finalSrc = src || '/images/default-food.png';

  return (
    <div className="inventory-image-box">
      <img
        src={finalSrc}
        alt={alt || 'ingredient'}
        className="inventory-real-image"
        onError={(e) => {
          e.currentTarget.src = '/images/default-food.png';
        }}
      />
    </div>
  );
};

const formatMoney = (value) => {
  const number = Number(value || 0);
  return `${number.toLocaleString('vi-VN')} đ`;
};

const formatDateVN = (dateStr) => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (Number.isNaN(date.getTime())) return dateStr;

  return `Ngày ${String(date.getDate()).padStart(2, '0')} Tháng ${String(
    date.getMonth() + 1
  ).padStart(2, '0')} Năm ${date.getFullYear()}`;
};

const normalizeStatus = (status) => {
  const value = (status || '').trim().toUpperCase();

  if (!value) return 'CHO';
  if (['CHO', 'PENDING'].includes(value)) return 'CHO';
  if (['DA_NHAP', 'RECEIVED', 'NHAN_HANG'].includes(value)) return 'DA_NHAP';
  if (['HOAN_TRA', 'RETURNED', 'CANCELLED'].includes(value)) return 'HOAN_TRA';

  return value;
};

const getStatusText = (status) => {
  const normalized = normalizeStatus(status);

  if (normalized === 'CHO') return 'Chờ';
  if (normalized === 'DA_NHAP') return 'Đã nhập';
  if (normalized === 'HOAN_TRA') return 'Hoàn trả';

  return normalized;
};

const isPendingStatus = (status) => normalizeStatus(status) === 'CHO';

function InventoryTrackingTab({ items, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!items.length) {
    return <Empty description="Chưa có dữ liệu tồn kho" />;
  }

  return (
    <div className="inventory-panel inventory-scroll-area">
      {items.map((item) => (
        <div
          key={item.ingredientId}
          className={`inventory-card ${item.lowStock ? 'inventory-card--warning' : ''}`}
        >
          <IngredientImage
            src={item.imageUrlIngredient}
            alt={item.ingredientName}
          />

          <div className="inventory-card__center">
            <div className="inventory-card__title">{item.ingredientName}</div>
            <div className="inventory-card__sub">Mã nguyên liệu: {item.ingredientId}</div>
            <div className="inventory-card__sub">
              Số lượng tồn: {item.currentStock} {item.unit || ''}
            </div>
            <div className="inventory-card__sub">Mức tối thiểu: {item.minStock}</div>
          </div>

          <div className="inventory-card__right">
            {item.lowStock ? 'Nguyên liệu sắp hết' : 'Tồn kho ổn định'}
          </div>
        </div>
      ))}
    </div>
  );
}

function ImportHistoryTab({
  receipts,
  loading,
  onCreateNew,
  supplierKeyword,
  setSupplierKeyword,
  fromDate,
  setFromDate,
  toDate,
  setToDate,
  ingredientId,
  setIngredientId,
  inventoryItems,
  handleSearch,
  handleReset,
  handleUpdateStatus,
  updatingReceiptId
}) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử nhập nguyên liệu</div>

      <div className="inventory-search-box">
        <div className="inventory-search-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input
              value={supplierKeyword}
              onChange={(e) => setSupplierKeyword(e.target.value)}
              placeholder="Nhập tên NCC"
            />
          </div>

          <div className="form-group">
            <label>Từ ngày:</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Đến ngày:</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Nguyên liệu:</label>
            <select
              value={ingredientId}
              onChange={(e) => setIngredientId(e.target.value)}
            >
              <option value="">-- Tất cả --</option>
              {inventoryItems.map((item) => (
                <option key={item.ingredientId} value={item.ingredientId}>
                  {item.ingredientId} - {item.ingredientName}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="inventory-search-actions">
  <button type="button" className="btn btn-primary" onClick={handleSearch}>
    Tìm kiếm
  </button>
  <button type="button" className="btn btn-secondary" onClick={handleReset}>
    Làm mới
  </button>
  <button type="button" className="btn btn-primary" onClick={onCreateNew}>
    Tạo phiếu mới
  </button>
</div>
      </div>

      {!receipts.length ? (
        <Empty description="Chưa có phiếu nhập" />
      ) : (
        receipts.map((receipt) => {
          const totalPrice = (receipt.details || []).reduce((sum, item) => {
            return sum + Number(item.quantityImport || 0) * Number(item.importPrice || 0);
          }, 0);

          const normalizedStatus = normalizeStatus(receipt.status);
          const locked = !isPendingStatus(normalizedStatus);
          const isUpdating = updatingReceiptId === receipt.idReceipt;

          return (
            <div className="receipt-block" key={receipt.idReceipt}>
              <div className="receipt-block__header">
                <span>{receipt.idReceipt} - NCC: {receipt.supplierName || '---'}</span>
                <span>{formatDateVN(receipt.receiptDate)}</span>
              </div>

              <div className="receipt-block__body">
                <div className="receipt-block__items inventory-scroll-area small">
                  {(receipt.details || []).map((item, index) => (
                    <div className="receipt-item" key={`${receipt.idReceipt}-${index}`}>
                      <IngredientImage
                        src={item.imageUrlIngredient}
                        alt={item.ingredientName}
                      />

                      <div className="receipt-item__main">
                        <div className="receipt-item__code">{item.ingredientId}</div>
                        <div className="receipt-item__name">{item.ingredientName}</div>
                      </div>

                      <div className="receipt-item__meta">
                        <div>Số lượng nhập: <span>{item.quantityImport}</span></div>
                        <div>Đơn giá: <span>{formatMoney(item.importPrice)}</span></div>
                        <div>
                          Tổng tiền:{' '}
                          <span>
                            {formatMoney(
                              Number(item.quantityImport || 0) * Number(item.importPrice || 0)
                            )}
                          </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="receipt-actions">
                  {!locked ? (
                    <>
                      <button
                        type="button"
                        className="btn btn-danger"
                        onClick={() => handleUpdateStatus(receipt, 'HOAN_TRA')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Hoàn trả'}
                      </button>

                      <button
                        type="button"
                        className="btn btn-success"
                        onClick={() => handleUpdateStatus(receipt, 'DA_NHAP')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Nhận hàng'}
                      </button>
                    </>
                  ) : (
                    <div className={`status-badge status-badge--${normalizedStatus.toLowerCase()}`}>
                      Trạng thái: {getStatusText(normalizedStatus)}
                    </div>
                  )}

                  <div>Người tạo: {receipt.createdBy || '---'}</div>
                  <div className="receipt-total">Tổng giá: {formatMoney(totalPrice)}</div>
                </div>
              </div>
            </div>
          );
        })
      )}

    </div>
  );
}

function CreateImportTab({ inventoryItems, onBack, onCreated }) {
  const [supplier, setSupplier] = useState('');
  const [date, setDate] = useState('');
  const [createdBy, setCreatedBy] = useState(localStorage.getItem('username') || 'admin');
  const [rows, setRows] = useState([
    { ingredientId: '', quantityImport: 1, importPrice: 0 }
  ]);
  const [submitting, setSubmitting] = useState(false);

  const grandTotal = useMemo(() => {
    return rows.reduce((sum, row) => {
      return sum + Number(row.quantityImport || 0) * Number(row.importPrice || 0);
    }, 0);
  }, [rows]);

  const updateRow = (index, field, value) => {
    const next = [...rows];
    next[index][field] = value;
    setRows(next);
  };

  const addRow = () => {
    setRows([...rows, { ingredientId: '', quantityImport: 1, importPrice: 0 }]);
  };

  const removeRow = () => {
    if (rows.length <= 1) return;
    setRows(rows.slice(0, rows.length - 1));
  };

  const getIngredientInfo = (ingredientId) => {
    return inventoryItems.find((item) => item.ingredientId === ingredientId);
  };

  const handleSubmit = async () => {
    if (!supplier.trim()) {
      message.warning('Vui lòng nhập nhà cung cấp');
      return;
    }

    if (!date) {
      message.warning('Vui lòng chọn ngày lập phiếu');
      return;
    }

    const validRows = rows.filter((row) => row.ingredientId);

    if (!validRows.length) {
      message.warning('Vui lòng chọn ít nhất 1 nguyên liệu');
      return;
    }

    const payload = {
      supplierName: supplier,
      receiptDate: date,
      status: DEFAULT_RECEIPT_STATUS,
      createdBy,
      details: validRows.map((row) => ({
        ingredientId: row.ingredientId,
        quantityImport: Number(row.quantityImport || 0),
        importPrice: Number(row.importPrice || 0)
      }))
    };

    try {
      setSubmitting(true);
      await axios.post(`${API_BASE_URL}/inventory/receipts`, payload);
      message.success('Tạo phiếu nhập thành công');
      onCreated();
    } catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Tạo phiếu nhập thất bại');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="create-receipt-page">
      <div className="create-receipt-header">
        <button type="button" className="back-button" onClick={onBack}>↩</button>
        <div className="inventory-create-title">Tạo phiếu nhập nguyên liệu</div>
      </div>

      <div className="create-receipt-panel">
        <div className="create-top-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input value={supplier} onChange={(e) => setSupplier(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Ngày lập phiếu:</label>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Trạng thái:</label>
            <input value="Chờ" readOnly />
          </div>

          <div className="form-group">
            <label>Người tạo:</label>
            <input value={createdBy} onChange={(e) => setCreatedBy(e.target.value)} />
          </div>
        </div>

        <div className="create-list-header">
          <h3>Danh sách nguyên liệu nhập</h3>

          <div className="mini-actions">
            <button type="button" onClick={addRow}>Thêm</button>
            <button type="button" onClick={removeRow}>Xóa</button>
          </div>
        </div>

        <div className="inventory-scroll-area create-list">
          {rows.map((row, index) => {
            const ingredient = getIngredientInfo(row.ingredientId);
            const total = Number(row.quantityImport || 0) * Number(row.importPrice || 0);

            return (
              <div className="create-item" key={index}>
                <IngredientImage
                  src={ingredient?.imageUrlIngredient}
                  alt={ingredient?.ingredientName}
                />

                <div className="create-item__main">
                  <div className="meta-row">
                    <label>Nguyên liệu:</label>
                    <select
                      value={row.ingredientId}
                      onChange={(e) => updateRow(index, 'ingredientId', e.target.value)}
                    >
                      <option value="">-- Chọn nguyên liệu --</option>
                      {inventoryItems.map((item) => (
                        <option key={item.ingredientId} value={item.ingredientId}>
                          {item.ingredientId} - {item.ingredientName}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="create-item__name">
                    {ingredient?.ingredientName || 'Tên nguyên liệu'}
                  </div>

                  <div className="create-item__stock">
                    Số lượng tồn: {ingredient?.currentStock ?? 0} {ingredient?.unit || ''}
                  </div>
                </div>

                <div className="create-item__meta">
                  <div className="meta-row">
                    <label>Số lượng nhập:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.quantityImport}
                      onChange={(e) => updateRow(index, 'quantityImport', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Đơn giá:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.importPrice}
                      onChange={(e) => updateRow(index, 'importPrice', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Tổng tiền:</label>
                    <input value={formatMoney(total)} readOnly />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="create-footer">
          <div className="grand-total">
            <label>Thành tiền:</label>
            <input value={formatMoney(grandTotal)} readOnly />
          </div>

          <button
            type="button"
            className="submit-receipt-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? 'Đang gửi...' : 'Gửi phiếu'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ConsumptionHistoryTab({ groups, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!groups.length) {
    return (
      <div className="inventory-scroll-page">
        <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>
        <Empty description="Chưa có dữ liệu tiêu thụ nguyên liệu" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>

      {groups.map((group, groupIndex) => (
        <div className="receipt-block" key={`${group.date}-${groupIndex}`}>
          <div className="receipt-block__header">
            <span>{formatDateVN(group.date)}</span>
          </div>

          <div className="receipt-block__body">
            <div className="receipt-block__items inventory-scroll-area small">
              {(group.items || []).map((item, index) => (
                <div className="receipt-item" key={`${group.date}-${item.ingredientId}-${index}`}>
                  <IngredientImage
                    src={item.imageUrlIngredient}
                    alt={item.ingredientName}
                  />

                  <div className="receipt-item__main">
                    <div className="receipt-item__code">{item.ingredientId}</div>
                    <div className="receipt-item__name">{item.ingredientName}</div>
                    <div className="inventory-card__sub">
                      Tồn kho hiện tại: {item.currentStock} {item.unit || ''}
                    </div>
                  </div>

                  <div className="receipt-item__meta">
                    <div>
                      Số lượng đã tiêu thụ: <span>{item.consumedQuantity}</span>
                    </div>
                    <div>
                      Đơn vị: <span>{item.unit || '---'}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

export default function InventoryPage() {
  const [mainTab, setMainTab] = useState('tracking');
  const [importMode, setImportMode] = useState('history');

  const [inventoryItems, setInventoryItems] = useState([]);
  const [receipts, setReceipts] = useState([]);
  const [consumptionHistory, setConsumptionHistory] = useState([]);

  const [loadingInventory, setLoadingInventory] = useState(false);
  const [loadingReceipts, setLoadingReceipts] = useState(false);
  const [loadingConsumption, setLoadingConsumption] = useState(false);
  const [updatingReceiptId, setUpdatingReceiptId] = useState('');

  const [supplierKeyword, setSupplierKeyword] = useState('');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [ingredientId, setIngredientId] = useState('');

  const fetchInventoryReport = async () => {
    try {
      setLoadingInventory(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/report`);
      setInventoryItems(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy dữ liệu tồn kho!');
    } finally {
      setLoadingInventory(false);
    }
  };

  const fetchReceipts = async () => {
    try {
      setLoadingReceipts(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/receipts`);
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const fetchConsumptionHistory = async (fromDateParam, toDateParam) => {
    try {
      setLoadingConsumption(true);
      const params = {};
      if (fromDateParam) params.fromDate = fromDateParam;
      if (toDateParam) params.toDate = toDateParam;

      const res = await axios.get(`${API_BASE_URL}/inventory/consumption-history`, { params });
      setConsumptionHistory(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy lịch sử tiêu thụ nguyên liệu!');
    } finally {
      setLoadingConsumption(false);
    }
  };

  const searchReceipts = async () => {
    try {
      setLoadingReceipts(true);

      const params = {};
      if (supplierKeyword.trim()) params.supplierName = supplierKeyword.trim();
      if (fromDate) params.fromDate = fromDate;
      if (toDate) params.toDate = toDate;
      if (ingredientId) params.ingredientId = ingredientId;

      const res = await axios.get(`${API_BASE_URL}/inventory/receipts/search`, { params });
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi tìm phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const resetSearch = async () => {
    setSupplierKeyword('');
    setFromDate('');
    setToDate('');
    setIngredientId('');
    await fetchReceipts();
  };

  useEffect(() => {
    fetchInventoryReport();
    fetchReceipts();
    fetchConsumptionHistory();
  }, []);

const handleCreated = async () => {
  setImportMode('history');
  await fetchInventoryReport();
  await fetchReceipts();
  await fetchConsumptionHistory();
};

  const handleUpdateStatus = async (receipt, nextStatus) => {
    if (!isPendingStatus(receipt.status)) {
      message.warning('Phiếu này đã cập nhật trạng thái, không thể đổi lại.');
      return;
    }

    const payload = {
      supplierName: receipt.supplierName,
      receiptDate: receipt.receiptDate,
      status: nextStatus,
      createdBy: receipt.createdBy,
      details: (receipt.details || []).map((item) => ({
        ingredientId: item.ingredientId,
        quantityImport: Number(item.quantityImport || 0),
        importPrice: Number(item.importPrice || 0)
      }))
    };

    try {
  setUpdatingReceiptId(receipt.idReceipt);
  await axios.put(`${API_BASE_URL}/inventory/receipts/${receipt.idReceipt}`, payload);
  message.success('Cập nhật trạng thái phiếu thành công');

  await fetchReceipts();
  await fetchInventoryReport();
  await fetchConsumptionHistory();
} catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Cập nhật trạng thái thất bại');
    } finally {
      setUpdatingReceiptId('');
    }
  };

  return (
    <div className="inventory-page">
      <div className="inventory-top-tabs">
        <button
          type="button"
          className={mainTab === 'tracking' ? 'active' : ''}
          onClick={() => setMainTab('tracking')}
        >
          Sổ theo dõi
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'import' ? 'active' : ''}
          onClick={() => setMainTab('import')}
        >
          Lịch sử nhập
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'consume' ? 'active' : ''}
          onClick={() => setMainTab('consume')}
        >
          Lịch sử tiêu thụ
          <br />
          nguyên liệu
        </button>
      </div>

      {mainTab === 'tracking' && (
        <InventoryTrackingTab items={inventoryItems} loading={loadingInventory} />
      )}

      {mainTab === 'import' && (
        <>
          {importMode === 'history' ? (
            <ImportHistoryTab
              receipts={receipts}
              loading={loadingReceipts}
              onCreateNew={() => setImportMode('create')}
              supplierKeyword={supplierKeyword}
              setSupplierKeyword={setSupplierKeyword}
              fromDate={fromDate}
              setFromDate={setFromDate}
              toDate={toDate}
              setToDate={setToDate}
              ingredientId={ingredientId}
              setIngredientId={setIngredientId}
              inventoryItems={inventoryItems}
              handleSearch={searchReceipts}
              handleReset={resetSearch}
              handleUpdateStatus={handleUpdateStatus}
              updatingReceiptId={updatingReceiptId}
            />
          ) : (
            <CreateImportTab
              inventoryItems={inventoryItems}
              onBack={() => setImportMode('history')}
              onCreated={handleCreated}
            />
          )}
        </>
      )}

      {mainTab === 'consume' && (
        <ConsumptionHistoryTab
          groups={consumptionHistory}
          loading={loadingConsumption}
        />
      )}
    </div>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { message, Empty, Spin } from 'antd';
import axios from 'axios';
import '../css/InventoryPage.css';

const API_BASE_URL = 'http://localhost:8081/api';
const DEFAULT_RECEIPT_STATUS = 'CHO';

const IngredientImage = ({ src, alt }) => {
  const finalSrc = src || '/images/default-food.png';

  return (
    <div className="inventory-image-box">
      <img
        src={finalSrc}
        alt={alt || 'ingredient'}
        className="inventory-real-image"
        onError={(e) => {
          e.currentTarget.src = '/images/default-food.png';
        }}
      />
    </div>
  );
};

const formatMoney = (value) => {
  const number = Number(value || 0);
  return `${number.toLocaleString('vi-VN')} đ`;
};

const formatDateVN = (dateStr) => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (Number.isNaN(date.getTime())) return dateStr;

  return `Ngày ${String(date.getDate()).padStart(2, '0')} Tháng ${String(
    date.getMonth() + 1
  ).padStart(2, '0')} Năm ${date.getFullYear()}`;
};

const normalizeStatus = (status) => {
  const value = (status || '').trim().toUpperCase();

  if (!value) return 'CHO';
  if (['CHO', 'PENDING'].includes(value)) return 'CHO';
  if (['DA_NHAP', 'RECEIVED', 'NHAN_HANG'].includes(value)) return 'DA_NHAP';
  if (['HOAN_TRA', 'RETURNED', 'CANCELLED'].includes(value)) return 'HOAN_TRA';

  return value;
};

const getStatusText = (status) => {
  const normalized = normalizeStatus(status);

  if (normalized === 'CHO') return 'Chờ';
  if (normalized === 'DA_NHAP') return 'Đã nhập';
  if (normalized === 'HOAN_TRA') return 'Hoàn trả';

  return normalized;
};

const isPendingStatus = (status) => normalizeStatus(status) === 'CHO';

function InventoryTrackingTab({ items, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!items.length) {
    return <Empty description="Chưa có dữ liệu tồn kho" />;
  }

  return (
    <div className="inventory-panel inventory-scroll-area">
      {items.map((item) => (
        <div
          key={item.ingredientId}
          className={`inventory-card ${item.lowStock ? 'inventory-card--warning' : ''}`}
        >
          <IngredientImage
            src={item.imageUrlIngredient}
            alt={item.ingredientName}
          />

          <div className="inventory-card__center">
            <div className="inventory-card__title">{item.ingredientName}</div>
            <div className="inventory-card__sub">Mã nguyên liệu: {item.ingredientId}</div>
            <div className="inventory-card__sub">
              Số lượng tồn: {item.currentStock} {item.unit || ''}
            </div>
            <div className="inventory-card__sub">Mức tối thiểu: {item.minStock}</div>
          </div>

          <div className="inventory-card__right">
            {item.lowStock ? 'Nguyên liệu sắp hết' : 'Tồn kho ổn định'}
          </div>
        </div>
      ))}
    </div>
  );
}

function ImportHistoryTab({
  receipts,
  loading,
  onCreateNew,
  supplierKeyword,
  setSupplierKeyword,
  fromDate,
  setFromDate,
  toDate,
  setToDate,
  ingredientId,
  setIngredientId,
  inventoryItems,
  handleSearch,
  handleReset,
  handleUpdateStatus,
  updatingReceiptId
}) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử nhập nguyên liệu</div>

      <div className="inventory-search-box">
        <div className="inventory-search-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input
              value={supplierKeyword}
              onChange={(e) => setSupplierKeyword(e.target.value)}
              placeholder="Nhập tên NCC"
            />
          </div>

          <div className="form-group">
            <label>Từ ngày:</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Đến ngày:</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Nguyên liệu:</label>
            <select
              value={ingredientId}
              onChange={(e) => setIngredientId(e.target.value)}
            >
              <option value="">-- Tất cả --</option>
              {inventoryItems.map((item) => (
                <option key={item.ingredientId} value={item.ingredientId}>
                  {item.ingredientId} - {item.ingredientName}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="inventory-search-actions">
  <button type="button" className="btn btn-primary" onClick={handleSearch}>
    Tìm kiếm
  </button>
  <button type="button" className="btn btn-secondary" onClick={handleReset}>
    Làm mới
  </button>
  <button type="button" className="btn btn-primary" onClick={onCreateNew}>
    Tạo phiếu mới
  </button>
</div>
      </div>

      {!receipts.length ? (
        <Empty description="Chưa có phiếu nhập" />
      ) : (
        receipts.map((receipt) => {
          const totalPrice = (receipt.details || []).reduce((sum, item) => {
            return sum + Number(item.quantityImport || 0) * Number(item.importPrice || 0);
          }, 0);

          const normalizedStatus = normalizeStatus(receipt.status);
          const locked = !isPendingStatus(normalizedStatus);
          const isUpdating = updatingReceiptId === receipt.idReceipt;

          return (
            <div className="receipt-block" key={receipt.idReceipt}>
              <div className="receipt-block__header">
                <span>{receipt.idReceipt} - NCC: {receipt.supplierName || '---'}</span>
                <span>{formatDateVN(receipt.receiptDate)}</span>
              </div>

              <div className="receipt-block__body">
                <div className="receipt-block__items inventory-scroll-area small">
                  {(receipt.details || []).map((item, index) => (
                    <div className="receipt-item" key={`${receipt.idReceipt}-${index}`}>
                      <IngredientImage
                        src={item.imageUrlIngredient}
                        alt={item.ingredientName}
                      />

                      <div className="receipt-item__main">
                        <div className="receipt-item__code">{item.ingredientId}</div>
                        <div className="receipt-item__name">{item.ingredientName}</div>
                      </div>

                      <div className="receipt-item__meta">
                        <div>Số lượng nhập: <span>{item.quantityImport}</span></div>
                        <div>Đơn giá: <span>{formatMoney(item.importPrice)}</span></div>
                        <div>
                          Tổng tiền:{' '}
                          <span>
                            {formatMoney(
                              Number(item.quantityImport || 0) * Number(item.importPrice || 0)
                            )}
                          </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="receipt-actions">
                  {!locked ? (
                    <>
                      <button
                        type="button"
                        className="btn btn-danger"
                        onClick={() => handleUpdateStatus(receipt, 'HOAN_TRA')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Hoàn trả'}
                      </button>

                      <button
                        type="button"
                        className="btn btn-success"
                        onClick={() => handleUpdateStatus(receipt, 'DA_NHAP')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Nhận hàng'}
                      </button>
                    </>
                  ) : (
                    <div className={`status-badge status-badge--${normalizedStatus.toLowerCase()}`}>
                      Trạng thái: {getStatusText(normalizedStatus)}
                    </div>
                  )}

                  <div>Người tạo: {receipt.createdBy || '---'}</div>
                  <div className="receipt-total">Tổng giá: {formatMoney(totalPrice)}</div>
                </div>
              </div>
            </div>
          );
        })
      )}

    </div>
  );
}

function CreateImportTab({ inventoryItems, onBack, onCreated }) {
  const [supplier, setSupplier] = useState('');
  const [date, setDate] = useState('');
  const [createdBy, setCreatedBy] = useState(localStorage.getItem('username') || 'admin');
  const [rows, setRows] = useState([
    { ingredientId: '', quantityImport: 1, importPrice: 0 }
  ]);
  const [submitting, setSubmitting] = useState(false);

  const grandTotal = useMemo(() => {
    return rows.reduce((sum, row) => {
      return sum + Number(row.quantityImport || 0) * Number(row.importPrice || 0);
    }, 0);
  }, [rows]);

  const updateRow = (index, field, value) => {
    const next = [...rows];
    next[index][field] = value;
    setRows(next);
  };

  const addRow = () => {
    setRows([...rows, { ingredientId: '', quantityImport: 1, importPrice: 0 }]);
  };

  const removeRow = () => {
    if (rows.length <= 1) return;
    setRows(rows.slice(0, rows.length - 1));
  };

  const getIngredientInfo = (ingredientId) => {
    return inventoryItems.find((item) => item.ingredientId === ingredientId);
  };

  const handleSubmit = async () => {
    if (!supplier.trim()) {
      message.warning('Vui lòng nhập nhà cung cấp');
      return;
    }

    if (!date) {
      message.warning('Vui lòng chọn ngày lập phiếu');
      return;
    }

    const validRows = rows.filter((row) => row.ingredientId);

    if (!validRows.length) {
      message.warning('Vui lòng chọn ít nhất 1 nguyên liệu');
      return;
    }

    const payload = {
      supplierName: supplier,
      receiptDate: date,
      status: DEFAULT_RECEIPT_STATUS,
      createdBy,
      details: validRows.map((row) => ({
        ingredientId: row.ingredientId,
        quantityImport: Number(row.quantityImport || 0),
        importPrice: Number(row.importPrice || 0)
      }))
    };

    try {
      setSubmitting(true);
      await axios.post(`${API_BASE_URL}/inventory/receipts`, payload);
      message.success('Tạo phiếu nhập thành công');
      onCreated();
    } catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Tạo phiếu nhập thất bại');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="create-receipt-page">
      <div className="create-receipt-header">
        <button type="button" className="back-button" onClick={onBack}>↩</button>
        <div className="inventory-create-title">Tạo phiếu nhập nguyên liệu</div>
      </div>

      <div className="create-receipt-panel">
        <div className="create-top-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input value={supplier} onChange={(e) => setSupplier(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Ngày lập phiếu:</label>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Trạng thái:</label>
            <input value="Chờ" readOnly />
          </div>

          <div className="form-group">
            <label>Người tạo:</label>
            <input value={createdBy} onChange={(e) => setCreatedBy(e.target.value)} />
          </div>
        </div>

        <div className="create-list-header">
          <h3>Danh sách nguyên liệu nhập</h3>

          <div className="mini-actions">
            <button type="button" onClick={addRow}>Thêm</button>
            <button type="button" onClick={removeRow}>Xóa</button>
          </div>
        </div>

        <div className="inventory-scroll-area create-list">
          {rows.map((row, index) => {
            const ingredient = getIngredientInfo(row.ingredientId);
            const total = Number(row.quantityImport || 0) * Number(row.importPrice || 0);

            return (
              <div className="create-item" key={index}>
                <IngredientImage
                  src={ingredient?.imageUrlIngredient}
                  alt={ingredient?.ingredientName}
                />

                <div className="create-item__main">
                  <div className="meta-row">
                    <label>Nguyên liệu:</label>
                    <select
                      value={row.ingredientId}
                      onChange={(e) => updateRow(index, 'ingredientId', e.target.value)}
                    >
                      <option value="">-- Chọn nguyên liệu --</option>
                      {inventoryItems.map((item) => (
                        <option key={item.ingredientId} value={item.ingredientId}>
                          {item.ingredientId} - {item.ingredientName}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="create-item__name">
                    {ingredient?.ingredientName || 'Tên nguyên liệu'}
                  </div>

                  <div className="create-item__stock">
                    Số lượng tồn: {ingredient?.currentStock ?? 0} {ingredient?.unit || ''}
                  </div>
                </div>

                <div className="create-item__meta">
                  <div className="meta-row">
                    <label>Số lượng nhập:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.quantityImport}
                      onChange={(e) => updateRow(index, 'quantityImport', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Đơn giá:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.importPrice}
                      onChange={(e) => updateRow(index, 'importPrice', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Tổng tiền:</label>
                    <input value={formatMoney(total)} readOnly />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="create-footer">
          <div className="grand-total">
            <label>Thành tiền:</label>
            <input value={formatMoney(grandTotal)} readOnly />
          </div>

          <button
            type="button"
            className="submit-receipt-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? 'Đang gửi...' : 'Gửi phiếu'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ConsumptionHistoryTab({ groups, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
